import{d as e}from"./app.2e1eaa90.js";const a={},r=e('<h1 id="常用工具-utils" tabindex="-1"><a class="header-anchor" href="#常用工具-utils" aria-hidden="true">#</a> 常用工具 (Utils)</h1><div class="custom-container tip"><p class="custom-container-title">注意</p><p>尽管本页介绍的 API 由 koishi-utils 包提供，但你仍然可以直接从 koishi-core 中引入它们。</p></div><h2 id="字符串操作" tabindex="-1"><a class="header-anchor" href="#字符串操作" aria-hidden="true">#</a> 字符串操作</h2><h3 id="simplify-source" tabindex="-1"><a class="header-anchor" href="#simplify-source" aria-hidden="true">#</a> simplify(source)</h3><ul><li><strong>source:</strong> <code>string</code> 源文本</li><li>返回值: <code>string</code> 简体文本</li></ul><p>繁体转简体。</p><h3 id="traditionalize-source" tabindex="-1"><a class="header-anchor" href="#traditionalize-source" aria-hidden="true">#</a> traditionalize(source)</h3><ul><li><strong>source:</strong> <code>string</code> 源文本</li><li>返回值: <code>string</code> 繁体文本</li></ul><p>简体转繁体。</p><h3 id="capitalize-source" tabindex="-1"><a class="header-anchor" href="#capitalize-source" aria-hidden="true">#</a> capitalize(source)</h3><ul><li><strong>source:</strong> <code>string</code> 源文本</li><li>返回值: <code>string</code> 首字母大写后的文本</li></ul><p>首字母大写。</p><h3 id="camelcase-source" tabindex="-1"><a class="header-anchor" href="#camelcase-source" aria-hidden="true">#</a> camelCase(source)</h3><ul><li><strong>source:</strong> <code>any</code> 要转换的内容</li><li>返回值: <code>any</code> 转换结果</li></ul><p>如果输入的是字符串，则将字符串转换成 camelCase；如果是数组或对象，则递归地将对象中的每个（可枚举）的键转换成 camelCase；其他情况不受影响。</p><h3 id="paramcase-source" tabindex="-1"><a class="header-anchor" href="#paramcase-source" aria-hidden="true">#</a> paramCase(source)</h3><p>如果输入的是字符串，则将字符串转换成 param-case；如果是数组或对象，则递归地将对象中的每个（可枚举）的键转换成 param-case；其他情况不受影响。</p><ul><li><strong>source:</strong> <code>any</code> 要转换的内容</li><li>返回值: <code>any</code> 转换结果</li></ul><h3 id="snakecase-source" tabindex="-1"><a class="header-anchor" href="#snakecase-source" aria-hidden="true">#</a> snakeCase(source)</h3><ul><li><strong>source:</strong> <code>any</code> 要转换的内容</li><li>返回值: <code>any</code> 转换结果</li></ul><p>如果输入的是字符串，则将字符串转换成 snake_case；如果是数组或对象，则递归地将对象中的每个（可枚举）的键转换成 snake_case；其他情况不受影响。</p><h2 id="集合操作" tabindex="-1"><a class="header-anchor" href="#集合操作" aria-hidden="true">#</a> 集合操作</h2><h3 id="contain-array1-array2" tabindex="-1"><a class="header-anchor" href="#contain-array1-array2" aria-hidden="true">#</a> contain(array1, array2)</h3><ul><li><strong>array1:</strong> <code>readonly any[]</code> 数组 1</li><li><strong>array2:</strong> <code>readonly any[]</code> 数组 2</li><li>返回值: <code>boolean</code> 数组 1 是否包含数组 2 的全部元素</li></ul><p>检测集合的包含关系。</p><h3 id="intersection-array1-array2" tabindex="-1"><a class="header-anchor" href="#intersection-array1-array2" aria-hidden="true">#</a> intersection(array1, array2)</h3><ul><li><strong>array1:</strong> <code>readonly any[]</code> 数组 1</li><li><strong>array2:</strong> <code>readonly any[]</code> 数组 2</li><li>返回值: <code>any[]</code> 两个数组的交集</li></ul><p>求两个集合的交集。</p><h3 id="difference-array1-array2" tabindex="-1"><a class="header-anchor" href="#difference-array1-array2" aria-hidden="true">#</a> difference(array1, array2)</h3><ul><li><strong>array1:</strong> <code>readonly any[]</code> 数组 1</li><li><strong>array2:</strong> <code>readonly any[]</code> 数组 2</li><li>返回值: <code>any[]</code> 两个数组的差集</li></ul><p>求两个集合的差集。</p><h3 id="union-array1-array2" tabindex="-1"><a class="header-anchor" href="#union-array1-array2" aria-hidden="true">#</a> union(array1, array2)</h3><ul><li><strong>array1:</strong> <code>readonly any[]</code> 数组 1</li><li><strong>array2:</strong> <code>readonly any[]</code> 数组 2</li><li>返回值: <code>any[]</code> 两个数组的并集</li></ul><p>求两个集合的并集。</p><h2 id="日期操作" tabindex="-1"><a class="header-anchor" href="#日期操作" aria-hidden="true">#</a> 日期操作</h2><h3 id="静态属性" tabindex="-1"><a class="header-anchor" href="#静态属性" aria-hidden="true">#</a> 静态属性</h3><ul><li>Time.millisecond</li><li>Time.second</li><li>Time.minute</li><li>Time.hour</li><li>Time.day</li><li>Time.week</li></ul><h3 id="time-getdatenumber-date" tabindex="-1"><a class="header-anchor" href="#time-getdatenumber-date" aria-hidden="true">#</a> Time.getDateNumber(date?)</h3><ul><li><strong>date:</strong> <code>Date</code> 日期对象，默认为 <code>new Date()</code></li><li>返回值: <code>number</code> UNIX 时间开始后的天数</li></ul><p>获取当前日期（从 UNIX 时间开始时计算）。</p><h3 id="time-fromdatenumber-value" tabindex="-1"><a class="header-anchor" href="#time-fromdatenumber-value" aria-hidden="true">#</a> Time.fromDateNumber(value)</h3><ul><li><strong>value:</strong> <code>number</code> UNIX 时间开始后的天数</li><li>返回值: <code>Date</code> 日期对象</li></ul><p>从 UNIX 时间开始后的天数计算日期对象。</p><h3 id="time-parsetime-source" tabindex="-1"><a class="header-anchor" href="#time-parsetime-source" aria-hidden="true">#</a> Time.parseTime(source)</h3><ul><li><strong>source:</strong> <code>string</code> 要解析的字符串</li></ul><p>将一个字符串解析成时间长度。</p><h3 id="time-parsedate-source" tabindex="-1"><a class="header-anchor" href="#time-parsedate-source" aria-hidden="true">#</a> Time.parseDate(source)</h3><ul><li><strong>source:</strong> <code>string</code> 要解析的字符串</li></ul><p>将一个字符串解析成 Date 对象。</p><h3 id="time-formattime-ms" tabindex="-1"><a class="header-anchor" href="#time-formattime-ms" aria-hidden="true">#</a> Time.formatTime(ms)</h3><ul><li><strong>ms:</strong> <code>number</code> 毫秒数</li></ul><h3 id="time-formattimeshort-ms" tabindex="-1"><a class="header-anchor" href="#time-formattimeshort-ms" aria-hidden="true">#</a> Time.formatTimeShort(ms)</h3><ul><li><strong>ms:</strong> <code>number</code> 毫秒数</li></ul><h3 id="time-formattimeinterval-time-interval" tabindex="-1"><a class="header-anchor" href="#time-formattimeinterval-time-interval" aria-hidden="true">#</a> Time.formatTimeInterval(time, interval?)</h3><ul><li><strong>time:</strong> <code>Date</code> 起始时间</li><li><strong>interval:</strong> <code>number</code> 时间间隔，单位为毫秒</li><li>返回值: <code>string</code></li></ul><h2 id="随机数操作" tabindex="-1"><a class="header-anchor" href="#随机数操作" aria-hidden="true">#</a> 随机数操作</h2><h3 id="random-uuid" tabindex="-1"><a class="header-anchor" href="#random-uuid" aria-hidden="true">#</a> Random.uuid()</h3><ul><li>返回值: <code>string</code> 生成的 UUID</li></ul><p>生成一个标准的 UUID (v5)。</p><h3 id="random-bool-probability" tabindex="-1"><a class="header-anchor" href="#random-bool-probability" aria-hidden="true">#</a> Random.bool(probability)</h3><ul><li><strong>probability:</strong> <code>number</code> 概率</li><li>返回值: <code>boolean</code> 随机布尔值</li></ul><p>生成一个随机布尔值，有 probability 的概率为 1。</p><h3 id="random-real-start-end" tabindex="-1"><a class="header-anchor" href="#random-real-start-end" aria-hidden="true">#</a> Random.real(start?, end)</h3><ul><li><strong>start:</strong> <code>number</code> 下界，默认为 0</li><li><strong>end:</strong> <code>end</code> 上界</li><li>返回值: <code>number</code> 一个 [start, end) 之间的随机实数</li></ul><p>生成一个随机实数。</p><h3 id="random-int-start-end" tabindex="-1"><a class="header-anchor" href="#random-int-start-end" aria-hidden="true">#</a> Random.int(start?, end)</h3><ul><li><strong>start:</strong> <code>number</code> 下界，默认为 0</li><li><strong>end:</strong> <code>end</code> 上界</li><li>返回值: <code>number</code> 一个 [start, end) 之间的随机整数</li></ul><p>生成一个随机实数。</p><h3 id="random-shuffle-array" tabindex="-1"><a class="header-anchor" href="#random-shuffle-array" aria-hidden="true">#</a> Random.shuffle(array)</h3><ul><li><strong>array:</strong> <code>T[]</code> 数组</li><li>返回值: <code>T[]</code> 新的数组</li></ul><p>随机打乱数组中的元素，返回新的数组。</p><h3 id="random-pick-array" tabindex="-1"><a class="header-anchor" href="#random-pick-array" aria-hidden="true">#</a> Random.pick(array)</h3><ul><li><strong>array:</strong> <code>readonly T[]</code> 数组</li><li>返回值: <code>T</code> 挑出的元素</li></ul><p>从数组中随机挑出一个元素，不改变原数组。</p><h3 id="random-multipick-array-count" tabindex="-1"><a class="header-anchor" href="#random-multipick-array-count" aria-hidden="true">#</a> Random.multiPick(array, count)</h3><ul><li><strong>array:</strong> <code>readonly T[]</code> 数组</li><li><strong>count:</strong> <code>number</code> 元素个数</li><li>返回值: <code>T[]</code> 挑出的元素列表</li></ul><p>从数组中随机挑出一些元素，不改变原数组。</p><h3 id="random-weightedpick-weights-value" tabindex="-1"><a class="header-anchor" href="#random-weightedpick-weights-value" aria-hidden="true">#</a> Random.weightedPick(weights, value?)</h3><ul><li><strong>weights:</strong> <code>Record&lt;T, number&gt;</code> 权重表</li><li><strong>value:</strong> <code>number</code> 一个 0 到 1 之间的随机数，默认为 <code>Math.random()</code></li><li>返回值: <code>T</code> 挑出的元素</li></ul><p>按照权重随机挑出一个元素。</p><h2 id="其他工具函数" tabindex="-1"><a class="header-anchor" href="#其他工具函数" aria-hidden="true">#</a> 其他工具函数</h2><h3 id="noop" tabindex="-1"><a class="header-anchor" href="#noop" aria-hidden="true">#</a> noop()</h3><ul><li>返回值: <code>void</code></li></ul><p>不进行任何操作（no operation）。</p><h3 id="sleep-ms" tabindex="-1"><a class="header-anchor" href="#sleep-ms" aria-hidden="true">#</a> sleep(ms?)</h3><ul><li><strong>ms:</strong> <code>number</code> 要等待的毫秒数</li><li>返回值: <code>Promise&lt;void&gt;</code></li></ul><p>等待一段时间。</p><h3 id="isinteger-value" tabindex="-1"><a class="header-anchor" href="#isinteger-value" aria-hidden="true">#</a> isInteger(value)</h3><ul><li><strong>value:</strong> <code>any</code> 要判断的值</li><li>返回值: <code>boolean</code> 是否为整数</li></ul><p>判断传入的值是否为整数。</p>',90);a.render=function(e,a){return r};export default a;
